<template>
  <div id="invoice" ref="invoiceRef" :class="['receipt', paperSize]">
    <div class="header head mx-auto">
      <h3>{{ nameStore }}</h3>
      <p>إيصال مبيعات - Sales Receipt</p>
      <p>{{ formattedDate }}</p>
      <hr />
    </div>

    <table>
      <thead>
        <tr>
          <th>المنتج<br />Product</th>
          <th>القياس<br />Size</th>
          <th>الكمية<br />Qty</th>
          <th>السعر<br />Price</th>
          <th>المجموع<br />Total</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="(item, index) in purchasedItems" :key="index">
          <td>{{ item.product_name }}</td>
          <td>{{ item.size }}</td>
          <td>
            {{ item.quantity - (item.returned_quantity || 0) }}
            <span v-if="item.returned_quantity > 0" class="returned-text">
              (راجع: {{ item.returned_quantity }})
            </span>
          </td>
          <td>{{ formatNumber(item.price) }}</td>
          <td>
            {{
              formatNumber(
                item.price * (item.quantity - (item.returned_quantity || 0))
              )
            }}
          </td>
        </tr>
      </tbody>
    </table>

     <hr />

    <div class="info_user" v-if="saleType == 1">
      <span style="display: flex; align-items: center; gap: 8px">
        <h4 style="font-weight: 400">الاسم : {{ name ?? "لايوجد" }}</h4>
        <h4 style="font-weight: 400">المدينة : {{ city ?? "لايوجد" }}</h4>
        <h4 style="font-weight: 400">رقم الهاتف : {{ phone ?? "لايوجد" }}</h4>
      </span>

      <hr />
    </div>

     <div class="totals">
      <p>
        <strong>المجموع الكلي للفاتورة الحالية- </strong>
        {{ formatNumber(adjustedTotalPrice) }} د.ع
      </p>
    </div>
    <div class="totals" v-if="saleType == 1">
      <p>
        <strong>  اجمالي المتبقي  الكلي - </strong>
        {{ formatNumber(remaining_amount) }} د.ع
      </p>
    </div>

    <span
      class="d-flex justify-center totals"
      v-if="saleType == 1 || saleType == 2"
    >
      <strong> نوع الشراء </strong>
      <span class="px-2"> - </span>
      <span v-if="saleType == 1"> آجل </span>
      <span v-else-if="saleType == 2"> توصيل </span>
    </span>

    <p v-if="hasReturns()" class="returns-note">
      (ملاحظة: تم خصم العناصر المسترجعة من الفاتورة)
    </p>

    <hr />
    <!-- هنا نضيف الباركود في النهاية -->
    <div class="barcode-container">
      <canvas ref="barcodeCanvas"></canvas>
    </div>
    <hr />

    <div class="footer">
      <p>شكراً لتسوقكم معنا! - Thank you!</p>
    </div>
  </div>
</template>

<script setup>
import moment from "moment-timezone";

import JsBarcode from "jsbarcode";
import { ref, onMounted, watch, computed, nextTick } from "vue";

const emit = defineEmits(["ready"]); // 👈 جديد

const props = defineProps({
  purchasedItems: {
    type: Array,
    default: null,
  },
  paperSize: {
    type: String,
    default: "size-58", // 'size-58' or 'size-80'
  },
  nameStore: {
    type: String,
    default: "",
  },
  saleType: {
    type: Number,
    required: true,
  },
  invoiceId: {
    type: String,
    required: true,
  },
  date: {
    type: String,
    required: true,
  },
  name: {
    type: String,
    required: false,
  },

  city: {
    type: String,
    required: false,
  },
  phone: {
    type: String,
    required: false,
  },
  
  remaining_amount: {
    type: String,
    required: false,
  },
});

// تنسيق التاريخ حسب توقيت بغداد
const formattedDate = moment(props.date)
  .tz("Asia/Baghdad")
  .format("YYYY-MM-DD hh:mm A");

function formatNumber(number) {
  return new Intl.NumberFormat("en-IQ", { maximumFractionDigits: 2 }).format(
    number
  );
}

const barcodeCanvas = ref(null);

const hasReturns = () => {
  return props.purchasedItems.some((item) => (item.returned_quantity || 0) > 0);
};

const generateBarcode = (value) => {
  if (!barcodeCanvas.value) return;
  JsBarcode(barcodeCanvas.value, value, {
    format: "code128",
    lineColor: "#000",
    width: 1.5, // صغّر عرض الخط قليلاً
    height: 40, // قلل الارتفاع
    margin: 5, // حدد المسافة الفارغة حول الباركود
    displayValue: true,
    fontSize: 12,
  });
};

const adjustedTotalPrice = computed(() => {
  return props.purchasedItems.reduce((acc, item) => {
    const soldQty = item.quantity - (item.returned_quantity || 0);
    return acc + item.price * soldQty;
  }, 0);
});

let emitted = false;

onMounted(async () => {
  generateBarcode(props.invoiceId);
  await nextTick();
  if (!emitted) {
    emitted = true;
    requestAnimationFrame(() => emit("ready"));
  }
});

watch(
  () => props.invoiceId,
  async (id) => {
    generateBarcode(id);
    await nextTick();
    if (!emitted) {
      emitted = true;
      requestAnimationFrame(() => emit("ready"));
    }
  }
);
</script>

<style scoped>
.receipt {
  font-family: monospace, "Tahoma", "Arial";
  font-size: 13px; /* أكبر قليلاً لزيادة الوضوح */
  direction: rtl;
  margin: auto;
  border: 1px dashed #aaa;
  padding: 5px;
}

.barcode-container {
  font-family: monospace, "Tahoma", "Arial" !important;
  font-size: 13px;
  text-align: center; /* توسيط الباركود أفقياً */
  margin-top: 10px;
  margin-bottom: 10px;
}

canvas {
  max-width: 100%;
  width: 200px;
  height: auto;
}
.size-58 {
  width: 58mm; /* بدل 210px */
  max-width: 58mm;
}

.size-80 {
  width: 80mm;
  max-width: 80mm;
}

.head {
  margin-top: 10px !important; /* يمكنك ضبط المسافة حسب حاجتك */
  page-break-after: avoid; /* يمنع الهيدر من الانقسام */
}

.header,
.footer {
  text-align: center;
  font-family: monospace, "Tahoma", "Arial";
}

table {
  font-family: monospace, "Tahoma", "Arial";
  width: 100%;
  border-collapse: collapse;
  margin-top: 8px;
  text-align: center;
  direction: rtl;
  table-layout: fixed;
}

thead th {
  font-family: monospace, "Tahoma", "Arial";
  border-bottom: 1px solid #000;
  font-weight: bold;
  font-size: 10px;
  padding: 4px 2px;
  vertical-align: middle; /* ✅ المحاذاة الرأسية */
  word-wrap: break-word;
  overflow-wrap: break-word;
  white-space: normal;
  line-height: 1.2; /* ✅ لتوازن السطرين */
}

thead th,
tbody td {
  padding: 6px 4px;
  font-size: 11px;
  word-wrap: break-word;
  overflow-wrap: break-word;
}

/* تعديل على الحاوية الرئيسية */
#invoice {
  width: 100%;
  max-width: 80mm;
  box-sizing: border-box;
  margin: 0 auto;
  padding: 0 4px;
}

td {
  text-align: center;
  padding: 4px 0;
}

hr {
  border-top: 1px dashed #000;
  margin: 6px 0;
}

.totals {
  text-align: center;
  font-size: 12px;
  font-weight: bold;
}
.returned-text {
  font-size: 13px; /* أو 14px للطباعة */
  font-weight: bold;
  text-decoration: underline; /* يوضحها أكثر */
  color: #000; /* أسود، يطبع أوضح */
}

.returns-note {
  font-size: 13px;
  font-weight: bold;
  border-top: 1px dashed #000; /* يفصلها عن باقي النص */
  margin-top: 5px;
  padding-top: 3px;
  color: #000;
}
</style>

<style>
/* في نفس ملف الفاتورة أو global.css */

@media print {
  /* اخفِ كل أبناء الـ body ما عدا حاوية الطباعة */
  body > *:not(#print-root) {
    display: none !important;
  }

  /* أظهر حاوية الطباعة ومحتواها فقط */
  #print-root {
    display: block !important;
  }

  /* إعدادات الصفحة الحرارية */
  @page {
    size: 80mm auto; /* الطول تلقائي حسب المحتوى */
    margin: 0mm;
  }

  table {
    width: 100% !important;
    table-layout: fixed !important;
  }

  #invoice {
    page-break-inside: avoid;
    padding: 0 4px !important;
    box-sizing: border-box !important;
    width: 100% !important;
    max-width: 80mm !important;
    margin: 0 auto !important;
  }
}
</style>
