<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      max-width="600"
      width="600"
    >
      <v-card class="mx-auto card" width="100%">
        <v-toolbar dark color="#624fc6">
          <v-btn
            icon
            fab
            color="#ffffff"
            x-small
            @click="$emit('popClose')"
            class="mr-1"
          >
            <Icon
              class="icon_download"
              icon="ic:outline-close"
              color="#ffffff"
              width="25"
            />
          </v-btn>

          <v-toolbar-title class="mx-auto d-flex justify-center pl-14">
            <h4 style="font-family: 'Cairo', sans-serif">مبيعات الآجل</h4>
          </v-toolbar-title>
        </v-toolbar>
        <v-card-text class="mt-4 d-flex justify-stert">
          <h4>اضف مستخدم لهذه فاتورة واضف الدفعه الاولية ان وجدت</h4>
        </v-card-text>
        <v-card-text class="d-flex justify-stert">
          <v-row>
            <v-col sm="12" md="12" lg="12">
              <v-menu
                v-model="menu"
                :close-on-content-click="false"
                :max-height="300"
                origin="top right"
                attach="body"
                offset-x
                right
              >
                <template #activator="{ props }">
                  <v-text-field
                    v-model="user"
                    @input="query_change"
                    v-bind="props"
                    class="font-weight-black"
                    label="إبحث عن المستخدم ..."
                    variant="outlined"
                    style="width: 100%"
                    color="#624fc6"
                    rounded
                    clearable
                    hide-details
                  />
                </template>

                <v-list class="list-font" v-if="debtor_users.length > 0">
                  <v-list-item
                    v-for="(user, index) in debtor_users"
                    :key="index"
                    @click="selectUser(user)"
                  >
                    <v-list-item-title style="text-align: right">
                      <h4 class="data_table">{{ user.name }}</h4>
                    </v-list-item-title>
                  </v-list-item>
                </v-list>
              </v-menu>
            </v-col>
            <v-col col="12" sm="12" md="12" lg="12">
              <v-text-field
                class="font-weight-black"
                :model-value="displayPrice"
                type="text"
                label="دفعة اولية"
                color="#624fc6"
                variant="outlined"
                rounded
                clearable
                autocomplete="price"
                lazy-rules
                persistent-hint
                hide-details="auto"
                @update:modelValue="onInput"
                @keypress="allowOnlyNumbers"
              />
            </v-col>
            <h4 class="mr-4">
              إجمالي المبلغ المستحق: {{ $filters.formatNumber(totalPrice) }} د.ع
            </h4>
          </v-row>
        </v-card-text>

        <v-card-actions class="mt-5 pb-5">
          <v-btn
            size="large"
            v-on:click="add_user"
            color="#624fc6"
            class="px-16 mx-auto border-btn"
            elevation="4"
            variant="flat"
            :loading="loading"
          >
            <h4 style="color: white; font-size: 17px">تاكيد</h4>
          </v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </v-row>
</template>
<script setup>
import { ref, watch, computed, defineProps } from "vue";
const emit = defineEmits(["popClose", "addSales"]);
import { useDebitsStore } from "@/stores/debits";
const debitsStore = useDebitsStore();

const payment = ref(null);

const menu = ref(false);
const user_id = ref("");
const user = ref(null);
const props = defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  totalPrice: {
    type: [String, Number],
    default: 0,
  },
});

const displayPrice = computed(() => {
  if (!payment.value) return "";
  return new Intl.NumberFormat("en-US").format(Number(payment.value));
});

const onInput = (val) => {
  const str = (val ?? "").toString();
  let onlyNumbers = str.replace(/\D/g, ""); // إزالة أي شيء غير رقم
  let numericValue = Number(onlyNumbers);

  // لا تسمح بكتابة أكثر من المبلغ المستحق
  if (numericValue > Number(props.totalPrice)) {
    // ترجع للقيمة السابقة بدل السماح بالتجاوز
    numericValue = Number(props.totalPrice);
  }

  payment.value = numericValue ? numericValue.toString() : "";
};

// منع أي حرف غير رقم أثناء الكتابة
const allowOnlyNumbers = (event) => {
  const key = event.key;

  // السماح فقط بالأرقام
  if (!/^[0-9]$/.test(key)) {
    event.preventDefault();
    return;
  }

  // التحقق من القيمة الحالية + المفتاح الجديد
  const currentValue = payment.value + key;
  const numericValue = Number(currentValue);

  // منع الكتابة إذا تجاوز الحد قبل حتى إدخاله
  if (numericValue > Number(props.totalPrice)) {
    event.preventDefault();
  }
};

const debtor_users = computed(() => debitsStore.debtor_user_add);

const query = computed({
  get: () => debitsStore.query2,
  set: (val) => (debitsStore.query2 = val),
});

function get_debtor_users() {
  debitsStore.get_debtor_users();
}

function selectUser(selectedUser) {
  user_id.value = selectedUser.id;
  user.value = selectedUser.name;
  menu.value = false;
}

function add_user() {
  if (user_id.value !== "") {
    let data = {};
    data["debtor_id"] = user_id.value;
    data["payment_amount"] = payment.value;
    data["user_type"] = 1;
    emit("addSales", data);
    emit("popClose");

    user_id.value = "";
    query.value = "";
    user.value = "";
    payment.value = "";
  }
}

let timerId = null;
function query_change() {
  menu.value = true;
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_debtor_users();
  }, 200);
}

// ✅ راقب فتح الـ dialog بدلاً من onMounted
watch(
  () => props.dialog,
  () => {
    get_debtor_users();
  }
);

watch(query, (newVal) => {
  if (newVal === null || newVal === "") {
    get_debtor_users();
  }
});
</script>
<style scoped>
.card {
  border-radius: 25px !important;
  box-shadow: 0px 0px 0px 0px !important;
}
</style>
